<template>
   <section>
    <loader :is-visible="isLoading"></loader>

    <div class="my-popups">
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">Global Task</h4>
                        <button type="button" class="close" v-on:click="Cancel">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>
                    <div class="modal-body">
                        <div class="row">
                            <div class="col-md-12 listing">
                                <div class="table-responsive table-fix-header dynamic-dashboard-add-report-table">
                                    <table :id="'tblReport'" class="table table-bordered mt-0">
                                        <thead class="thead-bg">
                                            <tr class="text-center">
                                                <th>
                                                    <div class="custom-control custom-checkbox">
                                                        <input class="custom-control-input"
                                                            type="checkbox" id="chkAlll" name="checkbox"
                                                            data-parent="no" style="display: none;"   v-model="selectAlll"
                                                             @change="toggleSelectAlll"
                                                             :disabled="IsSelectAllDisabled"
                                                             />
                                                        <label
                                                            class="custom-control-label universal-custom-control-label pt-1"
                                                            for="chkAlll"></label>
                                                    </div>
                                                </th>
                                                <th>{{ $t('TaskName') }}</th>
                                                <th>{{ $t('Isbillable') }}</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            <tr v-for="(Item, Index) in GlobalTaskData" :key="Index"
                                                class="text-center">
                                                <td class="text-center">
                                                    <div class="custom-control custom-checkbox">
                                                        <input class="setcheckall custom-control-input" type="checkbox"
                                                             name="checkbox" data-parent="no"
                                                            style="display: none;" v-model="Item.selected"
                                                            :id="'newchkAll_' + Index" @change="singleCheckBox(Item)"
                                                            :disabled="Item.IsDisable">                                                            
                                                        <label
                                                            class="custom-control-label universal-custom-control-label pt-1"
                                                            :for="'newchkAll_' + Index"></label>
                                                    </div>
                                                </td>
                                                <td>{{ Item.TaskNumber }} {{ Item.TASK_NAME }}</td>
                                                <td>{{ Item.IS_BILLABLE }}</td>

                                            </tr>
                                            <tr v-if="GlobalTaskData.length == 0">
                                                <td colspan="8">
                                                    <div class="text-center text-danger">{{
                                                        $t('NoRecordfound') }}</div>
                                                </td>
                                            </tr>
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                        </div>
                        <div class="clearfix"></div>
                        <div class="row flex-row-reverse mt-3">
                            <div class="col-lg-6 text-right">
                                <a href="javascript:;" class="submitbtn btn btn-primary  formbtn mr-2"
                                    v-on:click="Next()" title="Next"><i
                                        class="fa fa-angle-double-right pr-2"></i>{{ $t('Next') }}</a>
                                <a href="javascript:;" class="submitbtn btn btn-danger formbtn" v-on:click="Cancel()"
                                    title="Cancel"><i class="fa fa-close pr-2"></i>{{ $t('Cancel') }} </a>
                            </div>
                        </div>

                    </div>
                </div>
            </div>
        </div>
    </div>
   </section>
</template>
    <script>


    import DataService from '../../services/DataService';
    export default {
        props: {
            projectId: {
                type: String,
                require: true
            },

        },
        data() {
            return {
                userId: null,
                companyId: null,
                UserType: null,
                DataList: [],
                IsAllChecked: false,
                foundValue: null,
                searchString: '',
                isLoading: false,
                ProjectName: '',
                GlobalTaskData: [],
                SortBy: '',
                SortExp: '',
                PageSize: 10,
                PageNumber: 1,
                isPaged: 1,
                searchCondition: '',
                TotalRecords: 0,
                TotalPages: 1,
                CurrentPage: '',
                 statusValues: null,
                 IsDisable:false,
                selectedGlobalTeask: [],
                 selectAlll: false,
                 taskData:[],
            }
        },
        computed: {
            IsSelectAllDisabled() {
                // Disable select all if there are no enabled items
                const enabledItems = this.GlobalTaskData.filter(item => item.IsDisable === false);
                return enabledItems.length === 0;
            }
        },   
        created: function () {
            var vm = this;
            vm.userId = vm.GetUserInfo.ID;
            vm.companyId = vm.GetUserInfo.CompanyId;
            vm.UserType = vm.GetUserInfo.UserType;
            vm.FetchData();

        },
        methods: {
            toggleSelectAlll() {
                debugger
                const enabledItems = this.GlobalTaskData.filter(item => item.IsDisable === false);
                enabledItems.forEach((item) => {
                    item.selected = this.selectAlll;
                });
            },
            singleCheckBox(itm) {
                debugger
                const enabledItems = this.GlobalTaskData.filter(item => item.IsDisable === false);
                const selectedEnabledCount = enabledItems.filter(item => item.selected).length;
                // Update selectAll based on whether all enabled items are selected
                this.selectAlll = enabledItems.length > 0 && selectedEnabledCount === enabledItems.length;
            },
            FetchData: function () {
                var ths = this;
                ths.isLoading=true;
                if (ths.statusValues != null) {
                    var url = `statusIds=${ths.statusValues}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&projectId=&search=${ths.searchCondition}`;
                } else {
                    var url = `statusIds=&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&projectId=&search=${ths.searchCondition}`;
                }
             DataService.GlobalTaskListing(url).then((response) => {
                    if (response.data.result.DATA.length > 0) {
                        const listingData = ths.$parent.ListingData || [];
                        ths.GlobalTaskData = response.data.result.DATA.filter(item => item.status_name === 'Active').map(item => {
                        // Check if task already exists in parent's ListingData (compare as strings to handle type differences)
                        const exists = listingData.some(listTask =>
                            String(listTask.TaskId) === String(item.TASK_ID) &&
                            String(listTask.TaskName || '').trim().toLowerCase() === String(item.TASK_NAME || '').trim().toLowerCase()
                        );
                        return {
                            ...item,
                            selected: false,
                            IsDisable: exists
                        };
                        });
                    } else {
                        ths.GlobalTaskData = [];
                    }
                    ths.isLoading=false;
                    ths.selectAlll = false;
                    });
            },
            Next() {
                debugger
                var vm = this;
                var filteredClients = vm.GlobalTaskData.filter(task => task.selected == true);
                
                if (filteredClients.length === 0) {
                    vm.ShowAlert(vm.$t("PleaseSelectAtleastOneTask"), "warning", true, vm.$t("Alert"));
                    return;
                }
                
                vm.isLoading = true;               
                
                // Prepare tasks with all required fields for parent component
                var preparedTasks = filteredClients.map(task => {
                    // Ensure all required fields are present
                    return {
                        ...task,
                        TASK_ID: task.TASK_ID || task.task_id,
                        TASK_NAME: task.TASK_NAME || task.task_name || '',
                        TASK_DESC: task.TASK_DESC || task.TASK_DESCRIPTION || task.task_description || '',
                        TASK_RATE: task.TASK_RATE || task.task_rate || 0,
                        ESTIMATED_HOURS: task.ESTIMATED_HOURS || task.estimated_hours || 0,
                        IS_BILLABLE: task.IS_BILLABLE !== undefined ? task.IS_BILLABLE : false,
                        STATUS_ID: task.STATUS_ID || task.status_id || '',
                        PLANNED_START_DATE: task.PLANNED_START_DATE || task.planned_start_date || new Date().toISOString(),
                        PLANNED_END_DATE: task.PLANNED_END_DATE || task.planned_end_date || new Date().toISOString(),
                        WEIGHTAGE: task.WEIGHTAGE || task.weightage || 0,
                        current_progress: task.current_progress || task.CURRENT_PROGRESS || 0,
                        TOTAL_RECORDS: task.TOTAL_RECORDS || 0,
                        ROWNUMBER: task.ROWNUMBER || task.rownumber || 0
                    };
                });
                
                // Mark selected tasks as disabled so they can't be selected again
                filteredClients.forEach(task => {
                    task.IsDisable = true;
                    task.selected = false;
                });
                
                // Reset selectAll checkbox
                vm.selectAlll = false;
                
                // Reset selectedGlobalTeask and emit the selected tasks directly
                vm.selectedGlobalTeask = [preparedTasks];
                vm.$emit('next', vm.selectedGlobalTeask);
                vm.isLoading = false;
            },
            Cancel() {
                this.$emit('cancel');
            }
        },


    }

</script>